VALUES
  ('locality-d0d1b9a2-moex-00374', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '下列何者不是內部控制缺失？', '["缺乏適當的交易覆核", "員工經常踰越權限", "保障資產措施不足", "存貨種類繁多且容易過時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00375', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '會計師於查核財務報表時，接獲告發函指稱受查公司侵犯同一事務所查核簽證的另一家公司專利 權，而此一侵權行為可能衍生之訴訟及索賠金額重大。下列何者為會計師最可能採取的查核程序？', '["告知受查公司董事會，該會計師事務所因為利益衝突問題，考慮停止查核委任", "與受查公司管理階層及治理單位充分討論可能影響，評估相關侵權行為造成財務報導之重大不 實表達風險，並將討論過程做成工作底稿", "以會計師事務所具備的專業知識，判斷受查公司是否確實違反專利權，並正式通知公司管理階 層及治理單位可能的損害評估", "評估造成財務報導不實表達風險，如屬顯著風險，應通知利害關係人，以確保資訊的公開透明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00376', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '查核人員進行關係人交易查核前，應確認關係人資料庫的完整性。下列相關敘述何者錯誤？', '["向銀行函證，以直接取得銀行進行放款審查時之實質關係人（關聯人）名單", "向受查客戶索取書面聲明，聲明受查者已告知查核人員關係人之名稱", "請受查客戶所屬集團之集團管理階層，提供其依集團控制制度所編製的關係人名單", "與同一集團但不同企業個體之查核人員，交換及溝通已知之關係人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00377', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '下列有關重大不實表達風險、固有風險、控制風險、偵查風險、查核證據之敘述，何者錯誤？', '["查核人員應先評估固有風險及控制風險，訂定可接受之偵查風險，以決定取得查核證據之證實 程序，進而訂定可接受之查核風險", "重大不實表達風險是由固有風險及控制風險兩項風險所組成，並不包括偵查風險", "重大不實表達風險與查核證據數量兩者成正向關係，若評估重大不實表達風險偏高，查核人員 必須收集更多適切的查核證據", "查核人員只能依據受查者的實際情況評估固有風險及控制風險，且可以經由擴大證實程序取得 查核證據予以控制偵查風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00378', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '下列有關固有風險之敘述，何者正確？', '["固有風險與企業內部控制的設計有關", "固有風險與企業內部控制的執行力度有關", "固有風險越高，控制風險越高", "固有風險無法經由查核人員的查核規劃予以降低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00379', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '依據適用之財務報導架構，評估公司繼續經營會計基礎之採用是否適當，與企業繼續經營之能力，', '["查核人員", "公司管理階層", "公司治理單位", "查核人員專家"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00380', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '針對查核人員認定之某重大事項或交易，受查者管理階層拒絕納入其所提供之書面聲明中，則：', '["被查核人員視為違反誠信原則的不當舉動", "被查核人員視作財務報表無法允當表達的一項證據", "查核人員應將此情況視作重大不確定性存在而出具修正式意見", "查核人員應將此情況視作查核範圍受限而可能出具無法表示意見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00381', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '會計師首次受託查核時，下列何者對於本期查核工作較無影響？', '["上期受查者內部控制之設計及執行是否有效", "期初餘額之性質、不實表達之風險大小，及對本期報表之相對重要性大小", "上期財務報表受查者採用之會計政策", "上期財務報表是否經會計師查核，且其查核報告是否為保留意見"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00382', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '有關查核人員對證實分析性程序設計與執行之考量，下列敘述何者錯誤？', '["作為風險評估之分析性程序及協助作成整體結論之分析性程序，是所有財務報表查核案件必須 執行之查核程序", "對受查者兩年度財務報表進行差異比較分析非屬證實分析性程序，通常不可能作為證實程序之 查核證據", "證實分析性程序在所有案件中亦屬必要執行之程序", "利息支出、折舊等具有可推估特性，適合執行證實分析性程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00383', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '下列何項程序最可能發現公司有漏列銷貨及應收帳款金額之狀況？', '["函證應收帳款", "核對應收帳款總帳及明細帳", "複核應收帳款帳齡分析表", "自出貨單追查至日記帳分錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "e9b5affa9db7", "answer_pdf_sha1": "872f677a1228", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
